  pub const VK_IMAGE_CREATE_SPARSE_BINDING_BIT: Self = Self(1 << 0u64);
  ///Image should support sparse backing with partial residency
  pub const VK_IMAGE_CREATE_SPARSE_RESIDENCY_BIT: Self = Self(1 << 1u64);
  ///Image should support constant data access to physical memory ranges mapped into multiple locations of sparse images
  pub const VK_IMAGE_CREATE_SPARSE_ALIASED_BIT: Self = Self(1 << 2u64);
  ///Allows image views to have different format than the base image
  pub const VK_IMAGE_CREATE_MUTABLE_FORMAT_BIT: Self = Self(1 << 3u64);
  ///Allows creating image views with cube type from the created image
  pub const VK_IMAGE_CREATE_CUBE_COMPATIBLE_BIT: Self = Self(1 << 4u64);
