  pub const VK_IMAGE_CREATE_SPLIT_INSTANCE_BIND_REGIONS_BIT: Self = Self(1 << 6u64);
  #[cfg(feature = "VK_BASE_VERSION_1_1")]
  ///The 3D image can be viewed as a 2D or 2D array image
  pub const VK_IMAGE_CREATE_2D_ARRAY_COMPATIBLE_BIT: Self = Self(1 << 5u64);
  #[cfg(feature = "VK_BASE_VERSION_1_1")]
  pub const VK_IMAGE_CREATE_BLOCK_TEXEL_VIEW_COMPATIBLE_BIT: Self = Self(1 << 7u64);
  #[cfg(feature = "VK_BASE_VERSION_1_1")]
  pub const VK_IMAGE_CREATE_EXTENDED_USAGE_BIT: Self = Self(1 << 8u64);
  #[cfg(feature = "VK_BASE_VERSION_1_1")]
