  pub const VK_IMAGE_CREATE_PROTECTED_BIT: Self = Self(1 << 11u64);
  #[cfg(feature = "VK_BASE_VERSION_1_1")]
  pub const VK_IMAGE_CREATE_DISJOINT_BIT: Self = Self(1 << 9u64);
