  #[cfg(feature = "VK_KHR_maintenance2")]
  pub const VK_IMAGE_CREATE_EXTENDED_USAGE_BIT_KHR: Self = Self(1 << 8u64);
  #[cfg(feature = "VK_EXT_descriptor_heap")]
